import React, { useState, useRef } from "react";
//import logo from './logo.svg'
import "./App.css";
import { array_of_mutants, Original } from "./mutants";

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/

function App() {
  var [eredmeny, setEredmeny] = useState("-");
  var [killedMutants, setKilledMutants] = useState("-");
  var [testCaseNumber, setNumber] = useState(0);
  var [killed] = useState([]);
  //var [wrongTests, setWrongTests] = useState('')
  var [wrongTests] = useState([]);
  var [printWrongTests, setPrintWrongTests] = useState("");
  var [missing, setMissing] = useState("");
  var [result, setResult] = useState("");
  var [mutant] = useState([]);
  var [wrongSolution, setWrongSolution] = useState(false);

  var xInput = useRef();
  var yInput = useRef();
  if (wrongTests[0] === undefined) wrongTests[0] = "";
  //var zInput = useRef()

  function init() {
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
      mutant[i] = "";
    }
    setResult("");
    setMissing("");
    setNumber(0);
    setEredmeny(0);
    setWrongSolution(false);
    xInput.current.value = "";
    yInput.current.value = "";
    wrongTests[0] = "";
  }

  function callFunctions() {
    var x = +xInput.current.value;
    var y = +yInput.current.value;
    //var z = zInput.current.checked
    var mutantVacationDays = 0;
    var killedMutants1 = "";
    var vacationDays = Original(x, y);

    if (!(x === 0 && y === 0)) {
      setEredmeny(vacationDays); //!!!!!!!!!!!!! go to here!
      var superfluousTest = true;
      testCaseNumber++;
      for (var i = 0; i < array_of_mutants.length; i++) {
        if (!killed[i]) {
          mutantVacationDays = array_of_mutants[i](x, y).vDays;
          mutant[i] = array_of_mutants[i](x, y).mutant;

          if (vacationDays !== mutantVacationDays) {
            var j = i + 1;
            killedMutants1 = killedMutants1 + j + " ";
            killed[i] = true;
            mutant[i] = "";
            superfluousTest = false;
          }
        }
      }
      if (superfluousTest) {
        wrongTests[0] =
          "This test case is superfluous as it will not find any BVA-reated bug that haven't been found by your previous tests!";
        wrongSolution = true;
        console.log(" wrongSolution " + wrongSolution);
        //     console.log(wrongTests[0], ' superfluous')
      } else wrongTests[0] = "";
    }
    setWrongSolution(wrongSolution);
    setKilledMutants(killedMutants1);
    setNumber(testCaseNumber);
    //  setWrongTests(wrongTests)
  }

  function printResult() {
    var missingTests = false;
    var missedTestNumber = 0;

    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = "Missing test: " + mutant[i]; //'Some necessary test cases are missing.'
        missingTests = true;
        missedTestNumber++;
        //   console.log('not killed ', i)
      }
    }
    var ratio =
      100 - Math.round((missedTestNumber / array_of_mutants.length) * 100);
    printWrongTests = wrongTests;
    setPrintWrongTests(printWrongTests);

    if (testCaseNumber === 0) {
      result = "Please write your test cases!";
      alert("Please write your test cases!");
      return;
    } else if (
      !missingTests //&&
      //   !wrongSolution &&
      //   testCaseNumber > optimalTestCaseNumber
    ) {
      result = "Congratulation, you are very good at test design!";
      missing = "---";
      setMissing(missing);
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else
      result =
        "You have found " + ratio + "% of the potential bugs. Try again! ";
    setResult(result);
    setMissing(missing);
  }

  return (
    <div className="App">
      <header className="Back-header">
        <p class="Back">
          <a href="https://test-design.org/practical-exercises/">
            Back to Test Design Exercises
          </a>
        </p>
      </header>

      <header className="App-header">
        <p class="exercise">
          {" "}
          Read the specification below carefully. Add the test cases one by one.
          A test case ends with 'Next test'. You can continue adding test cases
          after 'Show my result'. <br />
          'Try again' starts a new test design session. &nbsp;&nbsp;You can use
          the{" "}
          <a href="https://exercises.test-design.org/general-predicate-testing/">
            GPT algorithm{" "}
          </a>
        </p>

        <p class="specification">
          {" "}
          <div style={{ textAlign: "center", fontSize: 20 }}>
            <b> Paid Vacation Days Calculation </b>
          </div>
          <b>R1</b> The number of vacation days depends on age and years of
          service. Every employee receives at least 22 days per year. Additional
          days are provided according to the following criteria: <br />
          <b>R1-1</b> Employees younger than 18 or at least 60 years, or
          employees with at least 30 years of service will receive 5 extra days.{" "}
          <br />
          <b>R1-2</b> Employees of age 60 or more with at least 30 years of
          service , receive 3 extra days, on top of possible additional days
          already given based on R1-1. <br />
          <b>R1-3</b> If an employee has at least 15 years of service, 2 extra
          days are given. These two days are also provided for employees of age
          45 or more. These extra days cannot be combined with the other extra
          days.
          <br /> <br />
          Display the vacation days. The ages are integers and calculated with
          respect to 31th December of the current year.&nbsp;&nbsp;{" "}
        </p>

        <p class="testcases">
          <div>
            {missing.length > 0 ? (
              <span data-harmony-id="Missing test">
                {" "}
                {missing} <br />
              </span>
            ) : (
              <span data-harmony-id="Wrong test">
                {" "}
                {wrongTests[0]} <br />
              </span>
            )}
          </div>
          <span data-harmony-id="result">{result}</span> <br />
          <br />
          Age:{" "}
          <input
            size="1"
            type="number"
            min="14"
            max="99"
            data-harmony-id="Age"
            ref={xInput}
          />
          &nbsp;&nbsp;&nbsp;&nbsp;Years of service:{" "}
          <input
            size="1"
            type="number"
            min="0"
            max="85"
            data-harmony-id="Service"
            ref={yInput}
          />
          &nbsp;&nbsp;&nbsp;&nbsp; Paid vacation days:{" "}
          <span data-harmony-id="Vacation days">{eredmeny}</span>
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <span
            data-harmony-id="Test case number"
            style={{ color: "mediumaquamarine" }}
          >
            Number of test cases: {testCaseNumber}
          </span>{" "}
          <br /> <br />
          <button
            class="button"
            data-harmony-id="Continue"
            onClick={callFunctions}
          >
            {" "}
            Next test{" "}
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Stop" onClick={printResult}>
            {" "}
            Show my result{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Try again" onClick={init}>
            {" "}
            Try again{" "}
          </button>{" "}
          <br />
          {/*killedMutant: <span>{killedMutants}</span> <br/> */}
        </p>
      </header>
    </div>
  );
}

export default App;
